ci:hover{border-color:var(--border2)}.sell-screen-v3 .ci-row1{display:flex;align-items:center;gap:7px}.sell-screen-v3 .ci-name{flex:1;font-size:12px;font-weight:600;color:var(--text);line-height:1.3}.sell-screen-v3 .ci-qty-wrap{display:flex;align-items:center;gap:3px}.sell-screen-v3 .ci-btn{width:22px;height:22px;border-radius:6px;background:rgba(255,255,255,.04);border:1px solid var(--border);color:var(--text2);cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:13px;transition:all .15s;flex-shrink:0}.sell-screen-v3 .ci-btn:hover{background:var(--gold-dim);color:var(--gold)}.sell-screen-v3 .ci-n{width:22px;text-align:center;font-size:12px;font-weight:700;font-family:'Space Mono',monospace;color:var(--text)}.sell-screen-v3 .ci-price{font-size:12px;font-weight:800;color:var(--gold);font-family:'Space Mono',monospace;white-space:nowrap}.sell-screen-v3 .ci-void-btn{background:none;border:none;color:var(--text3);cursor:pointer;font-size:13px;padding:2px;border-radius:4px;transition:all .15s;flex-shrink:0}.sell-screen-v3 .ci-void-btn:hover{color:var(--red);background:var(--red-dim)}.sell-screen-v3 .ci-row2{display:flex;align-items:center;gap:6px;margin-top:6px}.sell-screen-v3 .ci-station{font-size:9px;font-weight:800;padding:2px 6px;border-radius:999px;flex-shrink:0}.sell-screen-v3 .cs-k{background:rgba(249,181,28,.12);color:var(--gold)}.sell-screen-v3 .cs-b{background:var(--blue-dim);color:var(--blue)}.sell-screen-v3 .cs-c{background:rgba(62,207,142,.1);color:var(--green)}.sell-screen-v3 .ci-note-btn{font-size:10px;color:var(--text3);cursor:pointer;font-style:italic;transition:color .15s;background:none;border:none;text-align:left;padding:0}.sell-screen-v3 .ci-note-btn:hover{color:var(--blue)}.sell-screen-v3 .ci-kds-dot{width:7px;height:7px;border-radius:50%;flex-shrink:0;margin-left:auto}.sell-screen-v3 .kds-pending{background:var(--text3)}.sell-screen-v3 .kds-cooking{background:var(--orange)}.sell-screen-v3 .kds-ready{background:var(--green